using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string Text { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummaryService
{
    private static readonly HashSet<string> StopWords =
    [
        "a", "an", "the", "and", "or", "but", "in", "on", "at", "to", "for",
        "of", "with", "by", "is", "are", "was", "were", "be", "been", "being",
        "have", "has", "had", "do", "does", "did", "will", "would", "could",
        "should", "may", "might", "shall", "can", "this", "that", "these",
        "those", "it", "its", "i", "he", "she", "we", "they", "you", "my",
        "his", "her", "our", "their", "your", "not", "no", "from", "as", "so"
    ];

    public (string Summary, int OriginalCount, int SummaryCount) Summarize(string text, int maxSentences)
    {
        var sentences = SplitIntoSentences(text);

        if (sentences.Count <= maxSentences)
        {
            return (text.Trim(), sentences.Count, sentences.Count);
        }

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scored = ScoreSentences(sentences, wordFrequencies);

        // Take top-scored sentences but preserve their original order.
        var topIndices = scored
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .Order()
            .ToList();

        var summary = string.Join(" ", topIndices.Select(i => sentences[i].Trim()));

        return (summary, sentences.Count, topIndices.Count);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceBoundary()
            .Split(text)
            .Where(s => !string.IsNullOrWhiteSpace(s))
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (!StopWords.Contains(word.ToLowerInvariant()) && word.Length > 1)
                {
                    var lower = word.ToLowerInvariant();
                    frequencies[lower] = frequencies.GetValueOrDefault(lower) + 1;
                }
            }
        }

        return frequencies;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var scored = new List<(int Index, double Score)>();

        for (int i = 0; i < sentences.Count; i++)
        {
            var words = ExtractWords(sentences[i]);
            if (words.Count == 0)
            {
                scored.Add((i, 0));
                continue;
            }

            double score = words
                .Where(w => w.Length > 1)
                .Sum(w => wordFrequencies.GetValueOrDefault(w.ToLowerInvariant()));

            // Normalize by word count to avoid bias toward longer sentences.
            scored.Add((i, score / words.Count));
        }

        return scored;
    }

    private static List<string> ExtractWords(string text)
    {
        return WordPattern()
            .Matches(text)
            .Select(m => m.Value)
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\b[a-zA-Z']+\b")]
    private static partial Regex WordPattern();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController : ControllerBase
{
    private readonly DocumentSummaryService _summaryService;

    public SummaryController(DocumentSummaryService summaryService)
    {
        _summaryService = summaryService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var (summary, originalCount, summaryCount) = _summaryService.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = summaryCount
        });
    }
}

